function update(object, key, modify) {
  var value = object[key];
  var newValue = modify(value);
  var newObject = Object.assign({}, object);
  newObject[key] = newValue;
  return newObject;
}
function nestedUpdate(object, keys, modify) {
  if (keys.length === 0) return modify(object);
  var key1 = keys[0];
  var restOfKeys = keys.slice(1);
  return update(object, key1, (value1) => nestedUpdate(value1, restOfKeys, modify));
}

var cart = { shirt: { options: { color: 'blue', price: 20 } } };
var result = nestedUpdate(cart, ['shirt', 'options', 'price'], (p) => p + 5);
console.log(cart);
console.log(result);

